"use strict";(self.webpackChunkrrbtc_wiki_docusaurus=self.webpackChunkrrbtc_wiki_docusaurus||[]).push([[4486],{5991(e){e.exports=JSON.parse('{"tag":{"label":"wallet","permalink":"/tags/wallet","allTagsPath":"/tags","count":8,"items":[{"id":"entities/blockstream-green","title":"Blockstream Green","description":"Blockstream Green is a mobile and desktop Bitcoin wallet with optional 2FA multisig and hardware wallet integration.","permalink":"/entities/blockstream-green"},{"id":"entities/bluewallet","title":"BlueWallet","description":"Mobile Bitcoin wallet for iOS and Android. Supports both on-chain and Lightning. Originally included a custodial Lightning option; shifting toward non-custodial with Lightning Dev Kit (LDK) integration.","permalink":"/entities/bluewallet"},{"id":"entities/breez","title":"Breez","description":"Mobile Lightning wallet for iOS and Android. Built on Flutter. Non-custodial, Lightning-native, and includes a built-in marketplace plus point-of-sale (POS) support.","permalink":"/entities/breez"},{"id":"entities/electrum","title":"Electrum","description":"Electrum is one of the oldest Bitcoin wallets, using SPV to verify transactions without downloading the full blockchain. Its server implementation (ElectrumX, Electrs, Fulcrum) is widely bundled with node packages.","permalink":"/entities/electrum"},{"id":"entities/muun","title":"Muun","description":"Self-custodial Bitcoin wallet with a hybrid Lightning/on-chain model. Uses submarine swaps to enable Lightning payments without the user managing channels directly.","permalink":"/entities/muun"},{"id":"entities/phoenix","title":"Phoenix","description":"Self-custodial Lightning wallet by ACINQ. Designed to abstract channel management from the user while keeping keys on-device.","permalink":"/entities/phoenix"},{"id":"entities/sparrow-wallet","title":"Sparrow Wallet","description":"Sparrow Wallet is a desktop Bitcoin wallet focused on privacy, security, and flexibility. It supports single-sig and multisig setups and is designed for users who want full control over their coins and connections.","permalink":"/entities/sparrow-wallet"},{"id":"entities/zeus","title":"Zeus","description":"Mobile Lightning wallet and node management app. Connects to your own Lightning node (LND, Core Lightning, or Eclair) remotely, giving you full control without running a node on your phone.","permalink":"/entities/zeus"}],"unlisted":false}}')}}]);